// Built-in label bundles — the catalog of installable taxonomy "packs". A bundle
// is a themed set of LabelDefs a user installs in one click (via the board's Labels
// manager) to fit their role or life. Bundles are STATIC content (shipped in code,
// like the case TEMPLATES); installing one unions its labels into the live catalog
// (db.labels). Each label's `bundle` is stamped to its bundle id on install for
// provenance. The DATA below is generated by the design workflow and kept here as
// the single source of truth surfaced over GET /api/labels/bundles.
//
// To regenerate: re-run the design workflow, then splice its JSON in (from the
// repo root): `node scripts/gen-label-bundles.mjs <workflow-output.json>` — it
// rewrites the LABEL_BUNDLES literal below in place. Then refresh docs/reference/labels.md:
// `node scripts/gen-labels-doc.mjs`.

import type { CaseDomain, LabelColor, LabelDef } from "./types";

// A label inside a bundle definition — same shape as LabelDef minus the `bundle`
// provenance, which is stamped at install time.
export type BundleLabel = Omit<LabelDef, "bundle">;

export interface LabelBundle {
  id: string; // stable bundle id, e.g. "manager", "life-household-admin", "universal"
  name: string; // human display
  description: string; // who this bundle is for
  category: "role" | "life" | "universal";
  domain: CaseDomain; // default domain affinity for the pack
  labels: BundleLabel[];
}

// Lightweight summary surfaced to the UI / MCP (counts, not the full label list).
export interface BundleSummary {
  id: string;
  name: string;
  description: string;
  category: LabelBundle["category"];
  domain: CaseDomain;
  labelCount: number;
}

